#include "config.h"
#include "system.h"
#include "coretypes.h"
#include "backend.h"
#include "tree.h"
#include "gimple.h"
#include "cfghooks.h"
#include "tree-pass.h"
#include "ssa.h"
#include "gimple-pretty-print.h"
#include "tree-cfg.h"

namespace {

/* Pass data for the basic block counter pass.  */
const pass_data pass_data_count_bb =
{
  GIMPLE_PASS,        /* type */
  "count_bb",         /* name */
  OPTGROUP_NONE,      /* optinfo_flags */
  TV_TREE_SSA_OTHER,  /* tv_id */
  ( PROP_cfg ),       /* properties_required */
  0,                  /* properties_provided */
  0,                  /* properties_destroyed */
  0,                  /* todo_flags_start */
  0,                  /* todo_flags_finish */
};

/* A GIMPLE pass to count basic blocks per function.  */
class pass_count_bb : public gimple_opt_pass
{
public:
  pass_count_bb (gcc::context *ctxt)
    : gimple_opt_pass (pass_data_count_bb, ctxt)
  {}

  /* opt_pass methods: */
  bool gate (function *) final override
  {
    /* Always run this pass.  */
    return true;
  }

  unsigned int execute (function *fun) final override
  {
    basic_block bb;
    unsigned int bb_count = 0;

    /* Count all basic blocks in the function.  */
    FOR_EACH_BB_FN (bb, fun)
      {
        bb_count++;
      }

    /* Output debug information if dump_file is available.  */
    if (dump_file)
      {
        fprintf (dump_file, "Function %s has %u basic blocks\n",
                 function_name (fun), bb_count);
      }

    /* No code changes were made.  */
    return 0;
  }

  opt_pass * clone () final override { return new pass_count_bb (m_ctxt); }

}; // class pass_count_bb

} // anon namespace

/* Factory function to create the basic block counter pass.  */
gimple_opt_pass *
make_pass_count_bb (gcc::context *ctxt)
{
  return new pass_count_bb (ctxt);
}

/* Basic Block Counter GIMPLE Pass Header.
   Declaration of the make_pass_count_bb factory function.

   This file is part of GCC.  */

#ifndef GCC_COUNT_BB_PASS_H
#define GCC_COUNT_BB_PASS_H

class gimple_opt_pass;

namespace gcc {
  class context;
}

/* Factory function to create the basic block counter pass.  */
extern gimple_opt_pass *make_pass_count_bb (gcc::context *ctxt);

#endif /* GCC_COUNT_BB_PASS_H */

